private validateWebSocketConnection(connection: any) {
  // 从查询参数获取 token
  const token = connection.socket.request.query.token;

  if (!token) {
    connection.socket.close(1008, 'Missing authentication token');
    return false;
  }

  // 验证 token (与 API Key 相同)
  const validTokens = new Set(
    (process.env.DASHBOARD_API_KEYS || '').split(',').filter(Boolean)
  );

  if (!validTokens.has(token)) {
    connection.socket.close(1008, 'Invalid authentication token');
    return false;
  }

  return true;
}
