import { SecurityConfig } from '../config/security';

export abstract class BaseAgent {
  // ... 现有代码 ...

  /**
   * 安全执行 - 带输入验证和超时保护
   */
  async *executeSecure(prompt: string, timeout: number = 300000): AsyncGenerator<any> {
    // 1. 输入验证
    SecurityConfig.validateInput(prompt, 10000);

    // 2. 注入检测
    if (SecurityConfig.detectInjection(prompt)) {
      throw new Error('Potential injection attack detected');
    }

    // 3. 日志记录（不记录敏感信息）
    const sanitizedPrompt = SecurityConfig.sanitize(prompt);
    this.logSecurityEvent('execution_start', {
      agent: this.role,
      promptLength: prompt.length,
      sanitizedPrompt: sanitizedPrompt.substring(0, 100)
    });

    // 4. 超时保护
    const timeoutPromise = new Promise((_, reject) => 
      setTimeout(() => reject(new Error('Agent execution timeout')), timeout)
    );

    try {
      // 执行原有逻辑
      const generator = this.execute(prompt);
      const result = await Promise.race([
        this.collectGeneratorResults(generator),
        timeoutPromise
      ]);

      yield* this.parseResults(result);

    } catch (error) {
      this.logSecurityEvent('execution_error', {
        agent: this.role,
        error: error.message
      });
      throw error;
    }
  }

  /**
   * 记录安全事件
   */
  private logSecurityEvent(event: string, data: any): void {
    const logEntry = {
      timestamp: new Date().toISOString(),
      event,
      agent: this.role,
      data: SecurityConfig.sanitize(JSON.stringify(data))
    };

    // 写入安全日志文件
    const fs = require('fs');
    const logFile = path.join(process.cwd(), 'logs', 'security.log');

    fs.appendFile(logFile, JSON.stringify(logEntry) + '\n', (err: any) => {
      if (err) console.error('Failed to write security log:', err);
    });
  }
}
