// 敏感信息过滤器
class SensitiveDataFilter {
  private patterns = [
    /API[_-]?KEY["\']?\s*[:=]\s*["\']?[\w-]+/gi,
    /password["\']?\s*[:=]\s*["\']?[\w-]+/gi,
    /token["\']?\s*[:=]\s*["\']?[\w-]+/gi
  ];

  sanitize(input: string): string {
    return this.patterns.reduce((str, pattern) => 
      str.replace(pattern, '[REDACTED]'), input
    );
  }
}

// 在保存历史前过滤
